import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for p in fw['topLevelPackages']:
                pkgs[(name, p['id'])] = p['resolvedVersion']
    return pkgs

b, a = extract(baseline), extract(after)
all_keys = sorted(set(b) | set(a))
changes = [(k, b.get(k,'N/A'), a.get(k,'N/A')) for k in all_keys if b.get(k) != a.get(k)]
if changes:
    print('CHANGES:')
    for (proj,pkg), bv, av in changes:
        print(f'  {proj} | {pkg} | {bv} -> {av}')
else:
    print('No changes - conversion is fully version-neutral!')
"

